UIFriendBuiltItem = class("UIFriendBuiltItem", IGUIWindow)

function UIFriendBuiltItem:onLoad()
    print("UIFriendBuiltItem:onLoad()")
    self.icon = self:getChildWindow(0 , GUIType.UrlImage)
    self.icon:setDefaultImage("set:userItem.json image:icon")
    self.name = self:getChildWindow(1)
    self.sex = self:getChildWindow(2, GUIType.StaticImage)
    self.status = self:getChildWindow(3)
    self.expelBtn = self:getChildWindow(4):GetChildByIndex(0)
    self.expelBtn:registerEvent(GUIEvent.ButtonClick, function()
        self:onExpelButtonEvent()
    end)
    self.leaveBtn = self:getChildWindow(4):GetChildByIndex(1)
    self.leaveBtn:registerEvent(GUIEvent.ButtonClick, function()
        self:onLeaveButtonEvent()
    end)
    self.invitationBtn = self:getChildWindow(4):GetChildByIndex(2)
    self.invitationBtn:registerEvent(GUIEvent.ButtonClick, function()
        self:onInvitationButtonEvent()
    end)
    self.invitationBtn:SetVisible(false)

    self.ivMemberIcon = self:getChildWindow(0, GUIType.StaticImage, self:getChildWindow(5))
    self.tvMemberText = self:getChildWindow(5):GetChildByIndex(1)
    self.ivThreePoint = self:getChildWindow(6)
    self.ivThreePoint:SetVisible(false)
    self.data = {}
end

function UIFriendBuiltItem:onExpelButtonEvent()
    print("onExpelButton")
    local tips = string.format(Lang:getString("are_you_sure_expel"), tostring(self.data.memberName)) 
    GUITipDialog:onShowTipDialog(tips, GUITipDialog.TipType.COMMON, "", function(isSure)
            if isSure then
                MultiBuildData:postKickOut(GameData.userId, self.data.memberId, SkyBlockWeb.KickOutType.MASTER_KICK_OUT, false)
            end
        end)

    return
end

function UIFriendBuiltItem:onLeaveButtonEvent()
    print("onLeaveButton")
    local master = MultiBuildData:getBuildMaster()
    local tips = string.format(Lang:getString("are_you_sure_leave"), tostring(master.memberName)) 
    GUITipDialog:onShowTipDialog(tips, GUITipDialog.TipType.COMMON, "", function(isSure)
            if isSure then
                MultiBuildData:postKickOut(self.data.masterId, self.data.memberId, SkyBlockWeb.KickOutType.SELF_LEAVE, false)
            end
        end)
    return
end

function UIFriendBuiltItem:onInvitationButtonEvent()
    print("onInvitationButton")
    GUIFriend:getFriendInvitation()
    return
end

function UIFriendBuiltItem:getStatusText()
    if self.data.status == 0 then
        return Lang:getString("offline")
    end
    return Lang:getString("online")
end

function UIFriendBuiltItem:getIslandStatusText()
    if self:getCurItemIsIslandMaster() then
        return "Island_name"
    end
    return "Island_member_name"
end

function UIFriendBuiltItem:getSexIcon()
    if self.data.sex == 2 then
        return "set:skyblock_friend.json image:sex_girl"
    end
    return "set:skyblock_friend.json image:sex_boy"
end

function UIFriendBuiltItem:getMemberIcom()
    if self:getCurItemIsIslandMaster() then
        return "set:skyblock_friend.json image:built_island"
    end
    return "set:skyblock_friend.json image:built_member"
end

function UIFriendBuiltItem:getCurItemIsIslandMaster()
    if tostring(self.data.memberId) == tostring(self.data.masterId) then
        return true
    end
    return false
end

function UIFriendBuiltItem:setItemData(index)
    print("UIFriendBuiltItem setItemData index == "..index)
    local data = MultiBuildData:getMemberDataByIndex(index)
    if data then
        self:setDataUpdate(data)
        self.ivThreePoint:SetVisible(false)
        self.invitationBtn:SetVisible(false)
        self.leaveBtn:SetVisible(false)
        self.expelBtn:SetVisible(false)
        if self:getCurItemIsIslandMaster() == false then 
            if tostring(GameData.userId) == tostring(data.masterId) then
                self.expelBtn:SetVisible(true)
            elseif tostring(GameData.userId) == tostring(data.memberId) then
                self.leaveBtn:SetVisible(true)
            end
            return
        end
    end

    if index > #MultiBuildData.TogetherBuildData then
        self.icon:SetVisible(false)
        self.name:SetVisible(false)
        self.status:SetVisible(false)
        self.tvMemberText:SetVisible(false)
        self.ivMemberIcon:SetVisible(false)
        self.expelBtn:SetVisible(false)
        self.leaveBtn:SetVisible(false)
        self.invitationBtn:SetVisible(false)
        self.sex:SetVisible(false)
        self.ivThreePoint:SetVisible(true)
        if MultiBuildData:checkMeIsIslandMaster() then
            self.invitationBtn:SetVisible(true)
        end
    end
end

function UIFriendBuiltItem:setDataUpdate(data)
    self.data = data
    if self.data.memberPic then
        self.icon:setUrl(self.data.memberPic)
    end
    self.name:SetText(self.data.memberName)
    self.status:SetText(self:getStatusText())
    self.sex:SetImage(self:getSexIcon())
    self.tvMemberText:SetText(Lang:getString(self:getIslandStatusText()))
    self.ivMemberIcon:SetImage(self:getMemberIcom())
end